using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;
using ModelContextProtocol.Server;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    // The MCP SDK constructs a new instance per tool invocation, resolving
    // constructor parameters from the DI container automatically.
    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool(Name = "get_current_weather", ReadOnly = true),
     Description("Gets the current weather for a city. Returns temperature, condition, humidity, and wind.")]
    public async Task<string> GetCurrentWeather(
        [Description("City name, e.g. 'London' or 'New York'")] string city,
        CancellationToken cancellationToken)
    {
        using var client = _httpClientFactory.CreateClient("WeatherApi");
        var response = await client.GetAsync($"current.json?q={Uri.EscapeDataString(city)}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var weather = await response.Content.ReadFromJsonAsync<WeatherResponse>(cancellationToken);
        return $"{weather!.Location.Name}: {weather.Current.TempC}°C, " +
               $"{weather.Current.Condition.Text}, " +
               $"Humidity: {weather.Current.Humidity}%, " +
               $"Wind: {weather.Current.WindKph} km/h";
    }

    [McpServerTool(Name = "get_forecast", ReadOnly = true),
     Description("Gets a multi-day weather forecast for a city.")]
    public async Task<string> GetForecast(
        [Description("City name")] string city,
        [Description("Number of forecast days (1-3)")] int days,
        CancellationToken cancellationToken)
    {
        days = Math.Clamp(days, 1, 3);
        using var client = _httpClientFactory.CreateClient("WeatherApi");
        var response = await client.GetAsync(
            $"forecast.json?q={Uri.EscapeDataString(city)}&days={days}", cancellationToken);
        response.EnsureSuccessStatusCode();

        var forecast = await response.Content.ReadFromJsonAsync<ForecastResponse>(cancellationToken);
        var lines = forecast!.Forecast.ForecastDays.Select(d =>
            $"{d.Date}: {d.Day.AvgTempC}°C avg, {d.Day.Condition.Text}");
        return string.Join('\n', lines);
    }
}

// --- JSON response models ---

public record WeatherResponse(
    [property: JsonPropertyName("location")] LocationInfo Location,
    [property: JsonPropertyName("current")] CurrentWeather Current);

public record LocationInfo(
    [property: JsonPropertyName("name")] string Name);

public record CurrentWeather(
    [property: JsonPropertyName("temp_c")] double TempC,
    [property: JsonPropertyName("humidity")] int Humidity,
    [property: JsonPropertyName("wind_kph")] double WindKph,
    [property: JsonPropertyName("condition")] WeatherCondition Condition);

public record WeatherCondition(
    [property: JsonPropertyName("text")] string Text);

public record ForecastResponse(
    [property: JsonPropertyName("forecast")] ForecastData Forecast);

public record ForecastData(
    [property: JsonPropertyName("forecastday")] List<ForecastDay> ForecastDays);

public record ForecastDay(
    [property: JsonPropertyName("date")] string Date,
    [property: JsonPropertyName("day")] DayInfo Day);

public record DayInfo(
    [property: JsonPropertyName("avgtemp_c")] double AvgTempC,
    [property: JsonPropertyName("condition")] WeatherCondition Condition);

